The proposed function has three architecture problems.

1. The use case is fused to Next.js. `NextRequest` enters core logic and `NextResponse` leaves it, so the application action cannot run outside HTTP.
2. The use case is fused to Prisma. It imports `prisma` directly and uses Prisma models as its business data shape, so persistence details dictate the core boundary.
3. The business rule and orchestration are sitting in the adapter. Approval checking, total calculation, persistence, and HTTP translation all happen in one function.

The smallest production design is one domain rule module, one application use case, two inward-owned ports, thin adapters, and outer-layer wiring.

```ts
// domain/invoicing/order-for-invoice.ts
export type OrderForInvoice = {
  id: string;
  status: "APPROVED" | "PENDING" | "CANCELLED";
  lines: ReadonlyArray<{ amountCents: number }>;
};

export function assertApproved(order: OrderForInvoice): void {
  if (order.status !== "APPROVED") {
    throw new OrderNotApproved(order.id);
  }
}

export function calculateInvoiceTotal(order: OrderForInvoice): number {
  return order.lines.reduce((sum, line) => sum + line.amountCents, 0);
}

export class OrderNotApproved extends Error {
  constructor(orderId: string) {
    super(`Order ${orderId} is not approved`);
  }
}
```

```ts
// application/create-invoice.ts
import {
  OrderForInvoice,
  assertApproved,
  calculateInvoiceTotal,
} from "../domain/invoicing/order-for-invoice";

export type CreateInvoiceInput = {
  orderId: string;
};

export type CreateInvoiceOutput = {
  invoiceId: string;
  totalCents: number;
};

export interface LoadOrderForInvoice {
  load(orderId: string): Promise<OrderForInvoice | null>;
}

export interface SaveInvoice {
  save(draft: { orderId: string; totalCents: number }): Promise<{ id: string }>;
}

export class CreateInvoice {
  constructor(
    private readonly loadOrder: LoadOrderForInvoice,
    private readonly saveInvoice: SaveInvoice,
  ) {}

  async execute(input: CreateInvoiceInput): Promise<CreateInvoiceOutput> {
    const order = await this.loadOrder.load(input.orderId);
    if (!order) throw new Error("order not found");

    assertApproved(order);
    const totalCents = calculateInvoiceTotal(order);
    const invoice = await this.saveInvoice.save({ orderId: order.id, totalCents });

    return { invoiceId: invoice.id, totalCents };
  }
}
```

Translation happens only at the edges.

- Next.js route/controller: query string or route param -> `CreateInvoiceInput`; use case result/errors -> HTTP status and JSON body.
- Prisma order adapter: Prisma query result -> `OrderForInvoice`.
- Prisma invoice adapter: use-case save draft -> Prisma `invoice.create(...)`.

```ts
// interface-adapters/http/create-invoice-route.ts
import { NextRequest, NextResponse } from "next/server";
import { CreateInvoice } from "../../application/create-invoice";
import { OrderNotApproved } from "../../domain/invoicing/order-for-invoice";

export function createInvoiceRoute(useCase: CreateInvoice) {
  return async function POST(request: NextRequest): Promise<NextResponse> {
    try {
      const orderId = request.nextUrl.searchParams.get("orderId");
      const result = await useCase.execute({ orderId: orderId! });
      return NextResponse.json(
        { id: result.invoiceId, totalCents: result.totalCents },
        { status: 201 },
      );
    } catch (error) {
      if (error instanceof OrderNotApproved) {
        return NextResponse.json({ error: "not approved" }, { status: 409 });
      }
      throw error;
    }
  };
}
```

```ts
// interface-adapters/persistence/prisma-order-gateway.ts
import { prisma } from "@/infrastructure/prisma";
import { LoadOrderForInvoice } from "../../application/create-invoice";
import { OrderForInvoice } from "../../domain/invoicing/order-for-invoice";

export class PrismaOrderGateway implements LoadOrderForInvoice {
  async load(orderId: string): Promise<OrderForInvoice | null> {
    const record = await prisma.order.findUnique({
      where: { id: orderId },
      include: { lines: true },
    });

    if (!record) return null;

    return {
      id: record.id,
      status: record.status,
      lines: record.lines.map((line) => ({ amountCents: line.amountCents })),
    };
  }
}
```

```ts
// interface-adapters/persistence/prisma-invoice-gateway.ts
import { prisma } from "@/infrastructure/prisma";
import { SaveInvoice } from "../../application/create-invoice";

export class PrismaInvoiceGateway implements SaveInvoice {
  async save(draft: { orderId: string; totalCents: number }): Promise<{ id: string }> {
    const record = await prisma.invoice.create({ data: draft });
    return { id: record.id };
  }
}
```

Concrete wiring belongs in the outermost composition root, not in the use case.

```ts
// infrastructure/http/next-create-invoice.ts
import { CreateInvoice } from "../../application/create-invoice";
import { PrismaOrderGateway } from "../../interface-adapters/persistence/prisma-order-gateway";
import { PrismaInvoiceGateway } from "../../interface-adapters/persistence/prisma-invoice-gateway";
import { createInvoiceRoute } from "../../interface-adapters/http/create-invoice-route";

const useCase = new CreateInvoice(
  new PrismaOrderGateway(),
  new PrismaInvoiceGateway(),
);

export const POST = createInvoiceRoute(useCase);
```

Ownership is then clear.

- Domain owns the approval rule and invoice-total calculation.
- Application owns the use case, its input/output models, and the required interfaces.
- Adapters own translation between HTTP/Prisma and the inner models.
- Infrastructure owns object construction and framework wiring.

That is the smallest design that keeps the approval rule and invoice action independent from both Next.js and Prisma without adding broader operational concerns.
